"use client"

import { useEffect, useState } from 'react'

export default function DevicesPage() {
  const [data, setData] = useState<any>(null)
  const [error, setError] = useState('')
  const [busyMac, setBusyMac] = useState<string | null>(null)

  async function load() {
    const res = await fetch('/api/admin/devices', { credentials: 'include' })
    if (!res.ok) throw new Error('加载失败')
    setData(await res.json())
  }

  useEffect(() => {
    load().catch(() => setError('暂时无法获取设备列表，请确认以 root 登录后访问。'))
  }, [])

  async function act(mac: string, action: 'refresh' | 'reset-token') {
    setBusyMac(mac)
    try {
      await fetch(`/api/admin/devices/${mac}/${action}`, { method: 'POST', credentials: 'include' })
      await load()
    } finally {
      setBusyMac(null)
    }
  }

  return (
    <div>
      <div className="header-row"><h2>设备管理</h2></div>
      <div className="table-wrap">
        {error ? <div>{error}</div> : !data ? <div>加载中…</div> : (
          <table>
            <thead><tr><th>MAC</th><th>昵称</th><th>归属用户</th><th>语言</th><th>刷新间隔</th><th>最后刷新</th><th>操作</th></tr></thead>
            <tbody>
              {data.items.map((d: any) => (
                <tr key={d.mac}>
                  <td>{d.mac}</td>
                  <td>{d.nickname || '-'}</td>
                  <td>{d.owner_username || '-'}</td>
                  <td>{d.language || '-'}</td>
                  <td>{d.refresh_interval}</td>
                  <td>{d.last_refresh_at || '-'}</td>
                  <td style={{display:'flex', gap:8}}>
                    <button disabled={busyMac===d.mac} onClick={() => act(d.mac, 'refresh')}>强制刷新</button>
                    <button disabled={busyMac===d.mac} onClick={() => act(d.mac, 'reset-token')}>重置 Token</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  )
}
